// 三载体一致:纯计算,无 DOM/shadow 足迹
import pixelmatch from 'https://cdn.jsdelivr.net/npm/pixelmatch@7/+esm';
// data.img1 / data.img2:同尺寸 RGBA(canvas: ctx.getImageData(0,0,w,h).data)
const { width, height } = data;
const diff = new Uint8ClampedArray(width * height * 4);
const mismatch = pixelmatch(data.img1, data.img2, diff, width, height, { threshold: data.threshold ?? 0.1, includeAA: data.includeAA ?? false, diffMask: data.diffMask ?? false });
// mismatch = 不匹配像素数;diff 可 outCtx.putImageData(new ImageData(diff, width, height), 0, 0) 渲染
